/// Allowed destination domains (allowlist)
const ALLOWED_DOMAINS: &[&str] = &[
    "api.partner1.com",
    "api.partner2.com",
    "hooks.example.com",
    "webhook.site",
    "httpbin.org",
];

/// Maximum number of redirects allowed
const MAX_REDIRECTS: usize = 3;

/// Request timeout in seconds
const REQUEST_TIMEOUT_SECS: u64 = 10;

/// Maximum response body size (5 MB)
const MAX_RESPONSE_SIZE: usize = 5 * 1024 * 1024;

/// Check if an IPv4 address is private/internal/reserved
fn is_private_ipv4(ip: &Ipv4Addr) -> bool {
    ip.is_private()
        || ip.is_loopback()
        || ip.is_link_local()
        || ip.is_broadcast()
        || ip.is_unspecified()
        || ip.is_documentation()
        // 100.64.0.0/10 (Carrier-grade NAT)
        || (ip.octets()[0] == 100 && (ip.octets()[1] & 0xC0) == 64)
        // 192.0.0.0/24
        || (ip.octets()[0] == 192 && ip.octets()[1] == 0 && ip.octets()[2] == 0)
        // 198.18.0.0/15 (benchmarking)
        || (ip.octets()[0] == 198 && (ip.octets()[1] == 18 || ip.octets()[1] == 19))
        // 240.0.0.0/4 (reserved)
        || ip.octets()[0] >= 240
        // 0.0.0.0/8
        || ip.octets()[0] == 0
        // 169.254.0.0/16 (link-local, cloud metadata)
        || (ip.octets()[0] == 169 && ip.octets()[1] == 254)
}

/// Check if an IPv6 address is private/internal/reserved
fn is_private_ipv6(ip: &Ipv6Addr) -> bool {
    ip.is_loopback()
        || ip.is_unspecified()
        // IPv4-mapped IPv6 addresses
        || ip.to_ipv4_mapped().map_or(false, |v4| is_private_ipv4(&v4))
        // IPv4-compatible IPv6 addresses (deprecated but check anyway)
        || {
            let segments = ip.segments();
            if segments[0..6] == [0, 0, 0, 0, 0, 0] {
                let v4 = Ipv4Addr::new(
                    (segments[6] >> 8) as u8,
                    segments[6] as u8,
                    (segments[7] >> 8) as u8,
                    segments[7] as u8,
                );
                is_private_ipv4(&v4)
            } else {
                false
            }
        }
        // Unique local addresses (fc00::/7)
        || (ip.segments()[0] & 0xfe00) == 0xfc00
        // Link-local (fe80::/10)
        || (ip.segments()[0] & 0xffc0) == 0xfe80
        // Site-local (fec0::/10, deprecated)
        || (ip.segments()[0] & 0xffc0) == 0xfec0
        // Documentation (2001:db8::/32)
        || (ip.segments()[0] == 0x2001 && ip.segments()[1] == 0x0db8)
        // Teredo (2001::/32) - can encapsulate private IPv4
        || (ip.segments()[0] == 0x2001 && ip.segments()[1] == 0x0000)
}

/// Check if an IP address is private/internal
fn is_private_ip(ip: &IpAddr) -> bool {
    match ip {
        IpAddr::V4(v4) => is_private_ipv4(v4),
        IpAddr::V6(v6) => is_private_ipv6(v6),
    }
}

/// Validate the URL: check scheme, allowlisted domain, and resolved IPs
fn validate_url(url_str: &str) -> Result<Url, String> {
    // Parse the URL
    let parsed = Url::parse(url_str).map_err(|e| format!("Invalid URL: {}", e))?;

    // Only allow HTTPS
    if parsed.scheme() != "https" {
        return Err("Only HTTPS URLs are allowed".to_string());
    }

    // Ensure there's a host
    let host = parsed
        .host_str()
        .ok_or_else(|| "URL must have a host".to_string())?;

    // Block URLs with credentials
    if !parsed.username().is_empty() || parsed.password().is_some() {
        return Err("URLs with credentials are not allowed".to_string());
    }

    // Block non-standard ports (only allow 443)
    if let Some(port) = parsed.port() {
        if port != 443 {
            return Err("Only port 443 is allowed".to_string());
        }
    }

    // Check against allowlist
    let host_lower = host.to_lowercase();
    if !ALLOWED_DOMAINS.iter().any(|&d| host_lower == d) {
        return Err(format!("Domain '{}' is not in the allowlist", host));
    }

    // Check if the host is a raw IP address (block it - must use domain names)
    if host.parse::<IpAddr>().is_ok() {
        return Err("Direct IP addresses are not allowed; use domain names".to_string());
    }

    Ok(parsed)
}

/// Resolve the hostname and check all IPs are public
fn validate_resolved_ips(host: &str, port: u16) -> Result<(), String> {
    use std::net::ToSocketAddrs;

    let addr_str = format!("{}:{}", host, port);
    let addrs = addr_str
        .to_socket_addrs()
        .map_err(|e| format!("DNS resolution failed: {}", e))?;

    let addrs: Vec<_> = addrs.collect();
    if addrs.is_empty() {
        return Err("DNS resolution returned no addresses".to_string());
    }

    for addr in &addrs {
        if is_private_ip(&addr.ip()) {
            return Err(format!(
                "Resolved IP {} is in a private/reserved range",
                addr.ip()
            ));
        }
    }

    Ok(())
}

/// Custom redirect policy that validates each redirect target
fn create_redirect_policy() -> Policy {
    Policy::custom(move |attempt| {
        if attempt.previous().len() >= MAX_REDIRECTS {
            attempt.error(anyhow::anyhow!("Too many redirects"))
        } else {
            let url = attempt.url();

            // Validate redirect URL scheme
            if url.scheme() != "https" {
                return attempt.error(anyhow::anyhow!("Redirect to non-HTTPS URL blocked"));
            }

            // Validate redirect URL host is in allowlist
            if let Some(host) = url.host_str() {
                let host_lower = host.to_lowercase();
                if !ALLOWED_DOMAINS.iter().any(|&d| host_lower == d) {
                    return attempt.error(anyhow::anyhow!(
                        "Redirect to non-allowlisted domain blocked: {}",
                        host
                    ));
                }

                // Block raw IP redirects
                if host.parse::<IpAddr>().is_ok() {
                    return attempt
                        .error(anyhow::anyhow!("Redirect to raw IP address blocked"));
                }

                // Validate resolved IPs for redirect target
                let port = url.port().unwrap_or(443);
                if let Err(e) = validate_resolved_ips(host, port) {
                    return attempt.error(anyhow::anyhow!("Redirect IP validation failed: {}", e));
                }
            } else {
                return attempt.error(anyhow::anyhow!("Redirect URL has no host"));
            }

            attempt.follow()
        }
    })
}

async fn proxy_handler(
    _req: HttpRequest,
    query: web::Query<ProxyQuery>,
) -> HttpResponse {
    // Step 1: Validate the URL
    let parsed_url = match validate_url(&query.url) {
        Ok(url) => url,
        Err(e) => {
            return HttpResponse::BadRequest().json(serde_json::json!({
                "error": "Invalid URL",
                "detail": e
            }));
        }
    };

    // Step 2: Resolve DNS and validate IPs before making the request
    let host = parsed_url.host_str().unwrap(); // Safe: validated above
    let port = parsed_url.port().unwrap_or(443);

    if let Err(e) = validate_resolved_ips(host, port) {
        return HttpResponse::BadRequest().json(serde_json::json!({
            "error": "DNS validation failed",
            "detail": e
        }));
    }

    // Step 3: Build the HTTP client with strict settings
    let client = match reqwest::Client::builder()
        .redirect(create_redirect_policy())
        .timeout(Duration::from_secs(REQUEST_TIMEOUT_SECS))
        .connect_timeout(Duration::from_secs(5))
        .user_agent("WebhookProxy/1.0")
        // Don't trust system proxies
        .no_proxy()
        .build()
    {
        Ok(c) => c,
        Err(e) => {
            eprintln!("Failed to build HTTP client: {}", e);
            return HttpResponse::InternalServerError().json(serde_json::json!({
                "error": "Internal error",
                "detail": "Failed to initialize HTTP client"
            }));
        }
    };

    // Step 4: Make the request
    let response = match client.get(parsed_url.as_str()).send().await {
        Ok(resp) => resp,
        Err(e) => {
            eprintln!("Request failed for {}: {}", parsed_url, e);

            if e.is_timeout() {
                return HttpResponse::GatewayTimeout().json(serde_json::json!({
                    "error": "Upstream timeout",
                    "detail": "The upstream server did not respond in time"
                }));
            }

            if e.is_redirect() {
                return HttpResponse::BadGateway().json(serde_json::json!({
                    "error": "Redirect error",
                    "detail": format!("{}", e)
                }));
            }

            return HttpResponse::BadGateway().json(serde_json::json!({
                "error": "Upstream request failed",
                "detail": format!("{}", e)
            }));
        }
    };

    // Step 5: Read the response with size limits
    let status = response.status();
    let headers = response.headers().clone();

    // Check content-length header first if available
    if let Some(content_length) = headers.get(reqwest::header::CONTENT_LENGTH) {
        if let Ok(len_str) = content_length.to_str() {
            if let Ok(len) = len_str.parse::<usize>() {
                if len > MAX_RESPONSE_SIZE {
                    return HttpResponse::BadGateway().json(serde_json::json!({
                        "error": "Response too large",
                        "detail": format!("Response size {} exceeds maximum {}", len, MAX_RESPONSE_SIZE)
                    }));
                }
            }
        }
    }

    let body_bytes = match response.bytes().await {
        Ok(bytes) => {
            if bytes.len() > MAX_RESPONSE_SIZE {
                return HttpResponse::BadGateway().json(serde_json::json!({
                    "error": "Response too large",
                    "detail": format!("Response body exceeds {} bytes", MAX_RESPONSE_SIZE)
                }));
            }
            bytes
        }
        Err(e) => {
            eprintln!("Failed to read response body: {}", e);
            return HttpResponse::BadGateway().json(serde_json::json!({
                "error": "Failed to read upstream response",
                "detail": format!("{}", e)
            }));
        }
    };

    // Step 6: Build the proxied response
    let mut response_builder = HttpResponse::build(
        actix_web::http::StatusCode::from_u16(status.as_u16())
            .unwrap_or(actix_web::http::StatusCode::BAD_GATEWAY),
    );

    // Forward safe headers
    let safe_headers = [
        reqwest::header::CONTENT_TYPE,
        reqwest::header::CACHE_CONTROL,
        reqwest::header::ETAG,
        reqwest::header::LAST_MODIFIED,
    ];

    for header_name in &safe_headers {
        if let Some(value) = headers.get(*header_name) {
            if let Ok(header_value) = actix_web::http::header::HeaderValue::from_bytes(value.as_bytes()) {
                response_builder.insert_header((header_name.as_str(), header_value));
            }
        }
    }

    response_builder.body(body_bytes)
}

